import { execFile } from 'node:child_process'
import { readFile, access } from 'node:fs/promises'
import { resolve, dirname, basename, extname } from 'node:path'
import { promisify } from 'node:util'

const execFileAsync = promisify(execFile)

const pythonScript = resolve(process.cwd(), 'pdf-to-markdown', 'convert-docling.py')
const pythonBin = resolve(process.cwd(), 'pdf-to-markdown', '.venv', 'bin', 'python3')

export interface ConvertResult {
  ok: boolean
  markdown: string
  error?: string
}

async function fileExists(p: string): Promise<boolean> {
  try {
    await access(p)
    return true
  } catch {
    return false
  }
}

export async function convertPdfToMarkdown(inputPath: string): Promise<ConvertResult> {
  const outputPath = resolve(dirname(inputPath), `${basename(inputPath, extname(inputPath))}.md`)

  try {
    const { stdout, stderr } = await execFileAsync(
      pythonBin,
      [pythonScript, '--input', inputPath, '--output', outputPath],
      { timeout: 600000, maxBuffer: 50 * 1024 * 1024 }
    )

    if (stdout) console.log('Python converter output', stdout.trim())
    if (stderr) console.warn(`Python converter warning: ${stderr.trim()}`)

    if (!(await fileExists(outputPath))) {
      return { ok: false, markdown: '', error: `Conversion completed but output not found: ${outputPath}` }
    }

    const markdown = await readFile(outputPath, 'utf-8')
    return { ok: true, markdown }
  } catch (err) {
    return { ok: false, markdown: '', error: (err as Error).message }
  }
}

